import{_ as o,o as r,c as t,a3 as s}from"./chunks/framework.CjquFG0V.js";const f=JSON.parse('{"title":"40. Hours Of Work","description":"","frontmatter":{"title":"40. Hours Of Work","eba":"Biomedical Engineers 2025-2028","topics":["hours"]},"headers":[],"relativePath":"ebas/biomedical-engineers/hours-of-work/40-hours-of-work.md","filePath":"ebas/biomedical-engineers/hours-of-work/40-hours-of-work.md"}'),a={name:"ebas/biomedical-engineers/hours-of-work/40-hours-of-work.md"};function n(i,e,h,l,u,p){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="_40-hours-of-work" tabindex="-1">40. Hours Of Work <a class="header-anchor" href="#_40-hours-of-work" aria-label="Permalink to &quot;40. Hours Of Work&quot;">​</a></h1><p><strong>40.1</strong> All Employers excluding the Royal Children’s Hospital and the Royal Women’s Hospital</p><p><strong>(a)</strong> The hours for an ordinary week’s work shall be 38 hours, or be an average of 38 hours per week, in a two or four week period, or by mutual agreement, a five week period in the case of an Employee working ten hour shifts, and shall be worked:</p><p><strong>(i)</strong> in a week of five days in shifts of not more than seven hours and 36 minutes each; or</p><p><strong>(ii)</strong> by mutual agreement in a week of four days in shifts not more than ten hours each; or</p><p><strong>(iii)</strong> by mutual agreement, provided that the length of any ordinary shift shall not exceed ten hours.</p><p><strong>(b)</strong> Subject to the roster provisions 80 hours may be worked in any two consecutive weeks, but not more than 50 ordinary hours may be worked in any of such weeks.</p><p><strong>(c)</strong> With the exception of time occupied in having meals, the work of each shift shall be continuous.</p><p><strong>40.2</strong> The Royal Children’s Hospital and the Royal Women’s Hospital only:</p><p><strong>(a)</strong> The hours of work for an ordinary week’s work shall be 38 hours, or be an average of 38 hours per week, in a two or four week cycle, and shall be worked by mutual agreement, provided that the length of any ordinary shift is not less than six hours and does not exceed 12 hours.</p><p><strong>(b)</strong> Provided that any Employee required to work more than six consecutive periods of ordinary duty without 24 hours off duty shall be paid for the seventh and any further consecutive periods of duty work at a rate of treble time until they have been given 24 hours off duty. For the purposes of this subclause the working week shall commence at midnight on a Sunday.</p><p><strong>(c)</strong> The Employee must record all time worked on a Hospital timecard or other method determined by the Department.</p><p><strong>(d)</strong> Any dispute arising from a proposed variation of work patterns may be referred to the dispute settlement procedures under the Agreement.</p><p><strong>40.3</strong> Four Clear Days</p><p><strong>(a)</strong> An Employee is entitled to four clear days in each fortnight of a four week roster cycle free of duty, including on-call/recall work.</p><p><strong>(b)</strong> An Employer or Employee/s may propose that all Employees at a particular campus be covered by an alternate arrangement to that in clause 40.3(a). The proposal may be implemented where the Employer, the Union (or other Employee nominated representative) and the majority of affected Employees genuinely agree.</p><p><strong>(c)</strong> Any arrangements adopted in accordance with this subclause shall be recorded in writing and copies shall be provided to Employees to whom the arrangements apply.</p><p><strong>40.4</strong> 10-hour break between ordinary shifts</p><p><strong>(a)</strong> Subject to subclause 40.4(b), the Employer will provide an Employee with at least ten consecutive hours off duty between successive ordinary shifts, which will be reflected in any rosters that apply to the Employee. See also <a href="/eba/ebas/biomedical-engineers/hours-of-work/48-rest-period-after-overtime-recall-ten-hour-break.html">clause 48</a> for the periods off duty involving overtime.</p><p><strong>(b)</strong> Where for urgent operational issues there is not at least ten consecutive hours off duty between successive ordinary shifts as required at subclause 40.4(a), the Employee shall either:</p><p><strong>(i)</strong> be released from duty without loss of pay until the Employee has had ten consecutive hours off duty; or</p><p><strong>(ii)</strong> be paid at the rate of double time until released from duty for such rest period, where the employee is required to work without a ten-hour break on the instructions of the Employer.</p><p>Plain language terms: ordinary hours.</p>',23)])])}const c=o(a,[["render",n]]);export{f as __pageData,c as default};
